-- Fix noun-as-verb entries found in the 2026-06 verb_paths audit.
--
-- Hard errors: 'rollbacked' is not a word (entry deleted; 'roll back'
-- already exists), 'stale' is an adjective (entry becomes the phrase
-- 'go stale'), and the verb is spelled marshal/unmarshal (Marshall is
-- a proper noun). The timeout entry's sentences already used the
-- correct 'timed out', so the entry is renamed to the phrase 'time out'.
-- Five more noun forms taught nonstandard usage and are deleted in
-- favor of their existing phrase entries: backup (back up), checkout
-- (check out), login (log in), logout (log out), shutdown (shut down).

DELETE FROM verb_paths WHERE verb IN ('rollback', 'backup', 'checkout', 'login', 'logout', 'shutdown');
DELETE FROM verbs WHERE verb IN ('rollback', 'backup', 'checkout', 'login', 'logout', 'shutdown');

UPDATE verbs SET verb = 'go stale', normalized_verb = 'go stale', is_phrase = 1, meaning_zh = '变陈旧（缓存/数据）', updated_at = CURRENT_TIMESTAMP WHERE verb = 'stale';
UPDATE verbs SET verb = 'marshal', normalized_verb = 'marshal', updated_at = CURRENT_TIMESTAMP WHERE verb = 'marshall';
UPDATE verbs SET verb = 'unmarshal', normalized_verb = 'unmarshal', updated_at = CURRENT_TIMESTAMP WHERE verb = 'unmarshall';
UPDATE verbs SET verb = 'time out', normalized_verb = 'time out', is_phrase = 1, updated_at = CURRENT_TIMESTAMP WHERE verb = 'timeout';

